function getChangelog(){const e=localStorage.getItem(CONFIG.STORAGE_KEYS.CHANGELOG);return e?JSON.parse(e):[]}function saveChangelog(e){localStorage.setItem(CONFIG.STORAGE_KEYS.CHANGELOG,JSON.stringify(e))}function addChangelogEntry(e,t){const n=getChangelog();n.unshift({id:"log_"+Date.now(),time:(new Date).toISOString(),user:AppState.user?.name||"AP接龍工具系統",type:e,content:t}),saveChangelog(n),document.getElementById("tab-changelog").classList.contains("active")&&renderChangelog()}function getSheetLogs(){const e=AppState.sheetLogs||[],t={"新增":"add","編輯":"edit","刪除":"delete"};return e.map(e=>({id:`sheet_${e.memberId}_${e.date}_${e.action}`,time:`${e.date.slice(0,4)}-${e.date.slice(4,6)}-${e.date.slice(6,8)}T00:00:00`,user:e.editor,type:t[e.action]||e.action,content:`#${e.memberId} ${e.memberName}`,source:"sheet"}))}function renderChangelog(e=""){const t=document.getElementById("changelog-list"),n=document.getElementById("changelog-empty");let a=[...getChangelog(),...getSheetLogs()];const o=new Set;a=a.filter(e=>{const t=`${e.user}_${e.type}_${e.content}`;return!o.has(t)&&(o.add(t),!0)}),a.sort((e,t)=>new Date(t.time)-new Date(e.time)),e&&(a=a.filter(t=>t.time.startsWith(e))),n.style.display=0===a.length?"block":"none",t.style.display=0===a.length?"none":"flex";const s={add:"新增",edit:"編輯",delete:"刪除"};t.innerHTML=a.map(e=>{const t=new Date(e.time),n=t.toLocaleDateString("zh-TW")+" "+t.toLocaleTimeString("zh-TW",{hour:"2-digit",minute:"2-digit"}),a="sheet"===e.source?' <span class="cache-badge">共用</span>':"";return`\n      <div class="log-item">\n        <span class="log-time">${n}</span>\n        <span class="log-user">${escapeHtml(e.user)}${a}</span>\n        <span class="log-content">\n          <span class="badge" style="font-size:11px;">${s[e.type]||e.type}</span>\n          ${escapeHtml(e.content)}\n        </span>\n      </div>\n    `}).join("")}function initChangelog(){const e=document.getElementById("changelog-date-filter");e.addEventListener("change",()=>{renderChangelog(e.value)}),renderChangelog()}window.initChangelog=initChangelog,window.addChangelogEntry=addChangelogEntry;